  1	import React, { FC, useCallback, useState } from 'react';
  2	
  3	import useRegistryCredentials from '@catalog/utils/useRegistryCredentials/useRegistryCredentials';
  4	import { produceVMDisks, useWizardVMContext } from '@catalog/utils/WizardVMContext';
  5	import DataVolumeModel from '@kubevirt-ui/kubevirt-api/console/models/DataVolumeModel';
  6	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  7	import ConfirmActionMessage from '@kubevirt-utils/components/ConfirmActionMessage/ConfirmActionMessage';
  8	import DiskModal from '@kubevirt-utils/components/DiskModal/DiskModal';
  9	import {
 10	  DefaultFormValues,
 11	  V1DiskFormState,
 12	} from '@kubevirt-utils/components/DiskModal/utils/types';
 13	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 14	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 15	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
 16	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 17	import { ensurePath, isEmpty, kubevirtConsole } from '@kubevirt-utils/utils/utils';
 18	import { k8sDelete } from '@openshift-console/dynamic-plugin-sdk';
 19	import { ButtonVariant, Dropdown, DropdownItem, DropdownList } from '@patternfly/react-core';
 20	
 21	type DiskRowActionsProps = {
 22	  diskName: string;
 23	};
 24	
 25	const DiskRowActions: FC<DiskRowActionsProps> = ({ diskName }) => {
 26	  const { t } = useKubevirtTranslation();
 27	  const { tabsData, updateTabsData, updateVM, vm } = useWizardVMContext();
 28	  const { createModal } = useModal();
 29	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
 30	
 31	  const { decodedRegistryCredentials, updateRegistryCredentials } = useRegistryCredentials();
 32	  const defaultFormValues: DefaultFormValues = { registryCredentials: decodedRegistryCredentials };
 33	
 34	  const deleteBtnText = t('Detach');
 35	
 36	  const onDelete = useCallback(() => {
 37	    const volumeToDelete = vm.spec.template.spec.volumes.find((volume) => volume.name === diskName);
 38	
 39	    const vmWithDeletedDisk = produceVMDisks(vm, (draftVM) => {
 40	      if (volumeToDelete?.dataVolume?.name) {
 41	        draftVM.spec.dataVolumeTemplates = draftVM.spec.dataVolumeTemplates.filter(
 42	          (dataVolume) => dataVolume.metadata.name !== volumeToDelete.dataVolume.name,
 43	        );
 44	      }
 45	
 46	      draftVM.spec.template.spec.volumes = draftVM.spec.template.spec.volumes.filter(
 47	        (volume) => volume.name !== diskName,
 48	      );
 49	      draftVM.spec.template.spec.domain.devices.disks =
 50	        draftVM.spec.template.spec.domain.devices.disks.filter((disk) => disk.name !== diskName);
 51	    });
 52	
 53	    // check if disk has a created dataVolume that needs to be deleted (mainly for uploads)
 54	    const dataVolumeToDelete = tabsData?.disks?.dataVolumesToAddOwnerRef?.find(
 55	      (dv) => dv.metadata.name === volumeToDelete.persistentVolumeClaim.claimName,
 56	    );
 57	
 58	    if (dataVolumeToDelete) {
 59	      return k8sDelete({
 60	        model: DataVolumeModel,
 61	        resource: dataVolumeToDelete,
 62	      })
 63	        .catch(kubevirtConsole.error)
 64	        .finally(() => updateVM(vmWithDeletedDisk)) as Promise<V1VirtualMachine>;
 65	    }
 66	
 67	    return updateVM(vmWithDeletedDisk);
 68	  }, [diskName, tabsData?.disks?.dataVolumesToAddOwnerRef, updateVM, vm]);
 69	
 70	  const onDeleteModalToggle = () => {
 71	    createModal(({ isOpen, onClose }) => (
 72	      <TabModal<V1VirtualMachine>
 73	        headerText={t('Detach disk?')}
 74	        isOpen={isOpen}
 75	        obj={vm}
 76	        onClose={onClose}
 77	        onSubmit={onDelete}
 78	        submitBtnText={deleteBtnText}
 79	        submitBtnVariant={ButtonVariant.danger}
 80	      >
 81	        <ConfirmActionMessage action="detach" obj={{ metadata: { name: diskName } }} />
 82	      </TabModal>
 83	    ));
 84	  };
 85	
 86	  const handleEditSubmit = (newVM: V1VirtualMachine, diskFormState: V1DiskFormState) => {
 87	    const { registryCredentials } = diskFormState;
 88	    !isEmpty(registryCredentials) && updateRegistryCredentials(registryCredentials);
 89	    return updateVM(newVM);
 90	  };
 91	
 92	  const onEditModalToggle = () => {
 93	    createModal(({ isOpen, onClose }) => (
 94	      <DiskModal
 95	        onUploadedDataVolume={(dataVolume) =>
 96	          updateTabsData((draft) => {
 97	            ensurePath(draft, 'disks.dataVolumesToAddOwnerRef');
 98	            if (draft.disks) {
 99	              draft.disks.dataVolumesToAddOwnerRef = [
100	                ...(tabsData?.disks?.dataVolumesToAddOwnerRef || []),
101	                dataVolume,
102	              ];
103	            }
104	          })
105	        }
106	        defaultFormValues={defaultFormValues}
107	        editDiskName={diskName}
108	        isOpen={isOpen}
109	        onClose={onClose}
110	        onSubmit={handleEditSubmit}
111	        vm={vm}
112	      />
113	    ));
114	  };
115	
116	  const onToggle = () => setIsDropdownOpen((prevIsOpen) => !prevIsOpen);
117	
118	  return (
119	    <Dropdown
120	      isOpen={isDropdownOpen}
121	      onOpenChange={(open: boolean) => setIsDropdownOpen(open)}
122	      onSelect={() => setIsDropdownOpen(false)}
123	      toggle={KebabToggle({ id: 'toggle-id-disk', onClick: onToggle })}
124	    >
125	      <DropdownList>
126	        <DropdownItem key="disk-edit" onClick={onEditModalToggle}>
127	          {t('Edit')}
128	        </DropdownItem>
129	        <DropdownItem key="disk-delete" onClick={onDeleteModalToggle}>
130	          {deleteBtnText}
131	        </DropdownItem>
132	      </DropdownList>
133	    </Dropdown>
134	  );
135	};
136	
137	export default DiskRowActions;

